import React, { useMemo, useState } from 'react';
import './CharactersCatalog.css';

const characterList = [
  { id: 1, name: 'Guts', series: 'Berserk', popularity: 9.8, votes: 12450, image: 'https://placehold.co/360x240/1e1e2f/ffffff?text=Guts' },
  { id: 2, name: 'Sung Jin-Woo', series: 'Solo Leveling', popularity: 9.7, votes: 8920, image: 'https://placehold.co/360x240/0d3f4a/ffffff?text=Sung+Jin-Woo' },
  { id: 3, name: 'Naruto Uzumaki', series: 'Naruto', popularity: 9.5, votes: 15680, image: 'https://placehold.co/360x240/3d5a80/ffffff?text=Naruto' },
  { id: 4, name: 'Eren Yeager', series: 'Attack on Titan', popularity: 9.3, votes: 11230, image: 'https://placehold.co/360x240/4d2e2e/ffffff?text=Eren' }
];

const CharactersCatalog = () => {
  const [sortBy, setSortBy] = useState('popularity');
  const [searchTerm, setSearchTerm] = useState('');

  const characters = useMemo(() => {
    const filtered = characterList.filter(
      (c) =>
        c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.series.toLowerCase().includes(searchTerm.toLowerCase())
    );
    return filtered.sort((a, b) => {
      if (sortBy === 'votes') return b.votes - a.votes;
      if (sortBy === 'name') return a.name.localeCompare(b.name);
      return b.popularity - a.popularity;
    });
  }, [sortBy, searchTerm]);

  return (
    <div className="characters-catalog">
      <div className="catalog-header">
        <h2>Characters</h2>
        <div className="catalog-controls">
          <div className="search-box">
            <i className="fas fa-search"></i>
            <input value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} placeholder="Search characters..." />
          </div>
          <div className="sort-controls">
            <select value={sortBy} onChange={(e) => setSortBy(e.target.value)} className="sort-select">
              <option value="popularity">By popularity</option>
              <option value="votes">By votes</option>
              <option value="name">By name</option>
            </select>
          </div>
        </div>
      </div>

      <div className="characters-grid">
        {characters.map((character) => (
          <article key={character.id} className="character-card">
            <img src={character.image} alt={character.name} />
            <div className="character-content">
              <h3>{character.name}</h3>
              <p className="series">{character.series}</p>
              <div className="meta">
                <span><i className="fas fa-star"></i> {character.popularity}</span>
                <span><i className="fas fa-users"></i> {character.votes.toLocaleString()}</span>
              </div>
            </div>
          </article>
        ))}
      </div>
    </div>
  );
};

export default CharactersCatalog;
